  "sourcesContent": [".comment-view {\n\t--book-bg-image: url('/prueba.webp');\n\tposition: relative;\n\tmin-height: 100dvh;\n\tdisplay: grid;\n\tplace-items: center;\n\tpadding: 1.2rem;\n\toverflow: hidden;\n\tbackground:\n\t\tradial-gradient(circle at 18% 12%, rgba(255, 177, 89, 0.13), transparent 34%),\n\t\tradial-gradient(circle at 82% 88%, rgba(255, 120, 57, 0.1), transparent 28%),\n\t\tlinear-gradient(160deg, #120f0a 0%, #1d120f 44%, #2c1911 100%);\n}\n\n.comment-view::before {\n\tcontent: '';\n\tposition: absolute;\n\tinset: -12%;\n\tbackground-image: var(--book-bg-image);\n\tbackground-size: cover;\n\tbackground-position: center;\n\ttransform: scale(1.2);\n\tfilter: blur(12px) saturate(1.08);\n\topacity: 0.42;\n}\n\n.comment-view::after {\n\tcontent: '';\n\tposition: absolute;\n\tinset: 0;\n\tbackground:\n\t\tradial-gradient(circle at 20% 15%, rgba(255, 225, 178, 0.12), transparent 42%),\n\t\tlinear-gradient(160deg, rgba(10, 7, 5, 0.7), rgba(19, 12, 9, 0.9));\n}\n\n.comment-shell {\n\tposition: relative;\n\tz-index: 1;\n\twidth: min(1024px, 100%);\n\tdisplay: grid;\n\tgap: 1rem;\n}\n\n.back-link {\n\twidth: fit-content;\n\tcolor: #f7f3eb;\n\ttext-decoration: none;\n\tborder: 1px solid rgba(255, 225, 178, 0.22);\n\tbackground: rgba(33, 25, 18, 0.78);\n\tborder-radius: 999px;\n\tpadding: 0.45rem 0.95rem;\n\tfont-weight: 700;\n\tcursor: pointer;\n}\n\n.back-link:hover {\n\tbackground: rgba(44, 25, 17, 0.88);\n}\n\n.comment-card {\n\tdisplay: grid;\n\tgrid-template-columns: 300px minmax(0, 1fr);\n\tgap: 1.3rem;\n\tborder-radius: 1rem;\n\tpadding: 1rem;\n\tbackground: rgba(33, 25, 18, 0.78);\n\tborder: 1px solid rgba(255, 225, 178, 0.18);\n\tbox-shadow: 0 24px 70px rgba(0, 0, 0, 0.34);\n}\n\n.cover-column {\n\tborder-radius: 0.8rem;\n\toverflow: hidden;\n\tborder: 1px solid rgba(255, 225, 178, 0.18);\n\tbackground: rgba(12, 9, 7, 0.72);\n\taspect-ratio: 2 / 3;\n}\n\n.cover-column img {\n\twidth: 100%;\n\theight: 100%;\n\tobject-fit: cover;\n\tdisplay: block;\n}\n\n.content-column {\n\tdisplay: grid;\n\talign-content: center;\n\tgap: 1.1rem;\n\tcolor: #f7f3eb;\n}\n\n.eyebrow {\n\tmargin: 0;\n\ttext-transform: uppercase;\n\tletter-spacing: 0.09em;\n\tfont-size: 0.78rem;\n\tcolor: #ffd18b;\n}\n\n.content-column h1 {\n\tmargin: 0.1rem 0 0;\n\tfont-size: clamp(1.7rem, 3.2vw, 2.8rem);\n\tletter-spacing: -0.03em;\n}\n\n.meta {\n\tmargin: 0.35rem 0 0;\n\tcolor: #f4dcc2;\n}\n\n.comment-copy {\n\tmargin: 0;\n\tfont-size: clamp(1.05rem, 1.6vw, 1.25rem);\n\tline-height: 1.7;\n\tcolor: #f4dcc2;\n}\n\n.likes {\n\tdisplay: inline-flex;\n\talign-items: center;\n\tbackground: linear-gradient(90deg, rgba(255, 204, 122, 0.16), rgba(255, 157, 82, 0.14));\n\tborder: 1px solid rgba(255, 204, 122, 0.35);\n\tborder-radius: 999px;\n\tcolor: #ffd18b;\n\tpadding: 0.33rem 0.8rem;\n\tfont-weight: 700;\n}\n\n.status {\n\tmargin: 0;\n\tpadding: 0.65rem 0.75rem;\n\tborder-radius: 0.6rem;\n\tbackground: rgba(14, 10, 7, 0.58);\n\tborder: 1px solid rgba(255, 225, 178, 0.16);\n\tcolor: #f0e2cd;\n}\n\n.status.error {\n\tbackground: rgba(97, 33, 27, 0.55);\n\tborder-color: rgba(140, 60, 51, 0.9);\n\tcolor: #ffd9d2;\n}\n\n.related-section {\n\tdisplay: grid;\n\tgap: 0.9rem;\n\tpadding: 1rem;\n\tborder-radius: 1rem;\n\tbackground: rgba(33, 25, 18, 0.76);\n\tborder: 1px solid rgba(255, 225, 178, 0.16);\n}\n\n.related-loading {\n\tmargin: 0;\n\tpadding: 0.85rem 0.95rem;\n\tborder-radius: 0.75rem;\n\tborder: 1px solid rgba(255, 225, 178, 0.14);\n\tbackground: rgba(14, 10, 7, 0.58);\n\tcolor: #f0e2cd;\n}\n\n.related-head {\n\tdisplay: flex;\n\tjustify-content: space-between;\n\talign-items: center;\n\tgap: 0.75rem;\n\tpadding-bottom: 0.8rem;\n\tborder-bottom: 1px solid rgba(255, 225, 178, 0.14);\n\tcolor: #f7f3eb;\n}\n\n.related-head h2 {\n\tmargin: 0;\n\tfont-size: 1.1rem;\n\tletter-spacing: -0.02em;\n}\n\n.related-head span {\n\tfont-size: 0.9rem;\n\tcolor: #cfbca2;\n}\n\n.related-list {\n\tdisplay: grid;\n\tgap: 0.8rem;\n}\n\n.related-card {\n\tpadding: 0.9rem 1rem;\n\tborder-radius: 0.85rem;\n\tborder: 1px solid rgba(255, 225, 178, 0.14);\n\tbackground: rgba(14, 10, 7, 0.66);\n\tcolor: #f7f3eb;\n}\n\n.related-card-head {\n\tdisplay: flex;\n\tjustify-content: space-between;\n\tgap: 0.8rem;\n\talign-items: center;\n\tmargin-bottom: 0.45rem;\n}\n\n.related-card-head strong {\n\tfont-size: 0.98rem;\n\tcolor: #ffd18b;\n}\n\n.related-card-head span {\n\twhite-space: nowrap;\n\tfont-size: 0.82rem;\n\tcolor: #ffd18b;\n\tborder: 1px solid rgba(255, 204, 122, 0.28);\n\tbackground: rgba(255, 157, 82, 0.12);\n\tpadding: 0.22rem 0.6rem;\n\tborder-radius: 999px;\n}\n\n.related-card p {\n\tmargin: 0;\n\tline-height: 1.55;\n\tcolor: #f4dcc2;\n}\n\n.related-empty {\n\tmargin: 0;\n\tpadding: 0.95rem 1rem;\n\tborder-radius: 0.8rem;\n\tborder: 1px dashed rgba(255, 225, 178, 0.22);\n\tcolor: #cfbca2;\n\tbackground: rgba(14, 10, 7, 0.5);\n}\n\n@media (max-width: 760px) {\n\t.comment-view {\n\t\tpadding: 0.8rem;\n\t}\n\n\t.comment-shell {\n\t\tgap: 0.85rem;\n\t}\n\n\t.comment-card {\n\t\tgrid-template-columns: 1fr;\n\t\tgap: 1rem;\n\t\tpadding: 0.9rem;\n\t}\n\n\t.cover-column {\n\t\tmax-width: 210px;\n\t\twidth: 100%;\n\t}\n\n\t.content-column h1 {\n\t\tfont-size: clamp(1.55rem, 8vw, 2.1rem);\n\t}\n\n\t.comment-copy {\n\t\tfont-size: 1rem;\n\t\tline-height: 1.6;\n\t}\n\n\t.meta {\n\t\tfont-size: 0.95rem;\n\t}\n\n\t.related-section {\n\t\tpadding: 0.9rem;\n\t}\n\n\t.related-head {\n\t\talign-items: flex-start;\n\t\tflex-direction: column;\n\t}\n\n\t.related-card {\n\t\tpadding: 0.85rem;\n\t}\n}\n"],
